// Extract intel record and webhook params
const items = $input.all();
const item = items[0];

// Supabase returns array
const records = Array.isArray(item.json) ? item.json : [item.json];
const intel = records[0] || {};

// Get platform from original webhook body
// We need to access the webhook trigger's output - stored in execution context
// The platform comes through the chain from webhook trigger
const platform = $('Webhook - Receive Request').first().json.body?.platform || 'blog';
const intelId = $('Webhook - Receive Request').first().json.body?.intel_id || intel.id;

if (!intel.id) {
  throw new Error(`Intel record not found for id: ${intelId}`);
}

return [{
  json: {
    intel_id: intel.id,
    platform: platform,
    source: intel.source,
    content_type: intel.content_type,
    original_url: intel.original_url,
    original_title: intel.original_title,
    topic: intel.topic,
    keywords: intel.keywords || [],
    writing_style_notes: intel.writing_style_notes || '',
    engagement_score: intel.engagement_score || 0,
    raw_data: intel.raw_data || {}
  }
}];

