// Parse AI response and structure for Supabase insertion
const item = $input.first();
const response = item.json;

let parsed = {};
try {
  const content = response.choices[0].message.content;
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('Failed to parse OpenAI response: ' + e.message);
}

// Get intel_id from earlier in the chain
const intelData = $('Extract Intel + Platform').first().json;

// Validate and sanitize
const platform = parsed.platform || intelData.platform || 'blog';
const validPlatforms = ['blog', 'tiktok', 'instagram', 'facebook', 'linkedin'];
const safePlatform = validPlatforms.includes(platform) ? platform : 'blog';

// Ensure hooks is a proper array
let hooks = parsed.hooks || [];
if (typeof hooks === 'string') {
  try { hooks = JSON.parse(hooks); } catch (e) { hooks = [hooks]; }
}
if (!Array.isArray(hooks)) hooks = [];
hooks = hooks.slice(0, 5);

return [{
  json: {
    competitor_intel_id: intelData.intel_id || null,
    platform: safePlatform,
    status: 'pending',
    title_ar: parsed.title_ar || '',
    title_en: parsed.title_en || '',
    content_ar: parsed.content_ar || '',
    content_en: parsed.content_en || '',
    hooks: hooks,
    banana_image_prompt: parsed.banana_image_prompt || '',
    carousel_prompt: parsed.carousel_prompt || '',
    sora_video_prompt: parsed.sora_video_prompt || '',
    vue3_animation_prompt: parsed.vue3_animation_prompt || '',
    canva_brief: parsed.canva_brief || ''
  }
}];

// Prepare webhook response
const item = $input.first();
const insertedData = Array.isArray(item.json) ? item.json[0] : item.json;

return [{
  json: {
    suggestion_id: insertedData.id || null,
    platform: insertedData.platform || '',
    title_ar: insertedData.title_ar || '',
    title_en: insertedData.title_en || '',
    status: 'created',
    created_at: insertedData.created_at || new Date().toISOString(),
    competitor_intel_id: insertedData.competitor_intel_id || null
  }
}];
